  8вҶ’// queryBuilder constructs a dynamic WHERE clause with parameterized conditions.
  9вҶ’type queryBuilder struct {
 10вҶ’	conditions []string
 11вҶ’	args       []any
 12вҶ’}
 13вҶ’
 14вҶ’// add appends a condition with a single parameter. Use %d as the placeholder
 15вҶ’// position in the condition template (e.g., "type = $%d").
 16вҶ’func (qb *queryBuilder) add(conditionTemplate string, arg any) {
 17вҶ’	qb.args = append(qb.args, arg)
 18вҶ’	qb.conditions = append(qb.conditions, fmt.Sprintf(conditionTemplate, len(qb.args)))
 19вҶ’}
 20вҶ’
 21вҶ’// where returns the WHERE clause string (including "WHERE") or empty string if
 22вҶ’// no conditions were added.
 23вҶ’func (qb *queryBuilder) where() string {
 24вҶ’	if len(qb.conditions) == 0 {
 25вҶ’		return ""
 26вҶ’	}
 27вҶ’	return "WHERE " + strings.Join(qb.conditions, " AND ")
 28вҶ’}
 29вҶ’
 30вҶ’// nextParam returns the next parameter placeholder number without adding a condition.
 31вҶ’func (qb *queryBuilder) nextParam() int {
 32вҶ’	return len(qb.args) + 1
 33вҶ’}
 34вҶ’
 35вҶ’// sortFieldToColumn maps GraphQL sort field names to database column names.
 36вҶ’// Returns the column name and true if valid, or empty string and false if not.
 37вҶ’func sortFieldToColumn(field string) (string, bool) {
 38вҶ’	switch strings.ToUpper(field) {
 39вҶ’	case "CREATED_AT":
 40вҶ’		return "created_at", true
 41вҶ’	case "UPDATED_AT":
 42вҶ’		return "updated_at", true
 43вҶ’	case "CAPTURED_AT":
 44вҶ’		return "captured_at", true
 45вҶ’	case "TITLE":
 46вҶ’		return "title", true
 47вҶ’	default:
 48вҶ’		return "", false
 49вҶ’	}
 50вҶ’}
 51вҶ’
 52вҶ’// sortDirectionSQL returns "ASC" or "DESC". Defaults to "DESC" for invalid input.
 53вҶ’func sortDirectionSQL(dir string) string {
 54вҶ’	if strings.ToUpper(dir) == "ASC" {
 55вҶ’		return "ASC"
 56вҶ’	}
 57вҶ’	return "DESC"
 58вҶ’}
 59вҶ’
 60вҶ’// applyFilter adds filter conditions to the query builder.
 61вҶ’func applyFilter(qb *queryBuilder, f *Filter) {
 62вҶ’	if f == nil {
 63вҶ’		return
 64вҶ’	}
 65вҶ’	if len(f.Types) == 1 {
 66вҶ’		qb.add("type = $%d", f.Types[0])
 67вҶ’	} else if len(f.Types) > 1 {
 68вҶ’		qb.add("type = ANY($%d)", f.Types)
 69вҶ’	}
 70вҶ’	if len(f.Status) == 1 {
 71вҶ’		qb.add("status = $%d", f.Status[0])
 72вҶ’	} else if len(f.Status) > 1 {
 73вҶ’		qb.add("status = ANY($%d)", f.Status)
 74вҶ’	}
 75вҶ’	if len(f.Sensitivity) == 1 {
 76вҶ’		qb.add("sensitivity = $%d", f.Sensitivity[0])
 77вҶ’	} else if len(f.Sensitivity) > 1 {
 78вҶ’		qb.add("sensitivity = ANY($%d)", f.Sensitivity)
 79вҶ’	}
 80вҶ’	if len(f.Tags) > 0 {
 81вҶ’		qb.add("tags && $%d", f.Tags)
 82вҶ’	}
 83вҶ’	if f.Source != nil {
 84вҶ’		qb.add("source = $%d", *f.Source)
 85вҶ’	}
 86вҶ’	if f.DateFrom != nil {
 87вҶ’		qb.add("created_at >= $%d", *f.DateFrom)
 88вҶ’	}
 89вҶ’	if f.DateTo != nil {
 90вҶ’		qb.add("created_at <= $%d", *f.DateTo)
 91вҶ’	}
 92вҶ’}
 93вҶ’
 94вҶ’// clampLimit ensures limit is between 1 and maxLimit.
 95вҶ’func clampLimit(limit, maxLimit int) int {
 96вҶ’	if limit <= 0 {
 97вҶ’		return 20
 98вҶ’	}
 99вҶ’	if limit > maxLimit {
100вҶ’		return maxLimit
101вҶ’	}
102вҶ’	return limit
103вҶ’}
104вҶ’
105вҶ’// clampOffset ensures offset is non-negative.
106вҶ’func clampOffset(offset int) int {
107вҶ’	if offset < 0 {
108вҶ’		return 0
109вҶ’	}
110вҶ’	return offset
111вҶ’}
