 16вҶ’// itemColumns is the canonical SELECT column list for the items table.
 17вҶ’const itemColumns = `id, owner_id, type, status, sensitivity, title, content_text,
 18вҶ’	content_url, tags, metadata, auto_metadata, source, source_url,
 19вҶ’	created_at, updated_at, captured_at`
