 31вҶ’// GetByID returns a single item by ID and owner. Returns nil, nil if not found.
 32вҶ’func (s *Service) GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*Item, error) {
 33вҶ’	query := fmt.Sprintf(`SELECT %s FROM items WHERE owner_id = $1 AND id = $2`, itemColumns)
 34вҶ’	row := s.pool.QueryRow(ctx, query, ownerID, itemID)
 35вҶ’	it, err := scanItem(row)
 36вҶ’	if errors.Is(err, pgx.ErrNoRows) {
 37вҶ’		return nil, nil
 38вҶ’	}
 39вҶ’	if err != nil {
 40вҶ’		return nil, fmt.Errorf("item: get by id: %w", err)
 41вҶ’	}
 42вҶ’	return it, nil
 43вҶ’}
