 45вҶ’// List returns a page of items matching the given filter, sorted and paginated.
 46вҶ’func (s *Service) List(ctx context.Context, ownerID uuid.UUID, filter *Filter, limit, offset int, sort *Sort) (*SearchResult, error) {
 47вҶ’	limit = clampLimit(limit, maxLimit)
 48вҶ’	offset = clampOffset(offset)
 49вҶ’
 50вҶ’	qb := &queryBuilder{}
 51вҶ’	qb.add("owner_id = $%d", ownerID)
 52вҶ’	applyFilter(qb, filter)
 53вҶ’	whereClause := qb.where()
 54вҶ’
 55вҶ’	// Count total
 56вҶ’	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
 57вҶ’	var total int
 58вҶ’	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
 59вҶ’		return nil, fmt.Errorf("item: list count: %w", err)
 60вҶ’	}
 61вҶ’
 62вҶ’	// Determine sort
 63вҶ’	orderCol := "created_at"
 64вҶ’	orderDir := "DESC"
 65вҶ’	if sort != nil {
 66вҶ’		if col, ok := sortFieldToColumn(sort.Field); ok {
 67вҶ’			orderCol = col
 68вҶ’		}
 69вҶ’		orderDir = sortDirectionSQL(sort.Direction)
 70вҶ’	}
 71вҶ’
 72вҶ’	dataQuery := fmt.Sprintf(`SELECT %s FROM items %s ORDER BY %s %s LIMIT $%d OFFSET $%d`,
 73вҶ’		itemColumns, whereClause, orderCol, orderDir, qb.nextParam(), qb.nextParam()+1)
 74вҶ’	qb.args = append(qb.args, limit, offset)
 75вҶ’
 76вҶ’	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
 77вҶ’	if err != nil {
 78вҶ’		return nil, fmt.Errorf("item: list query: %w", err)
 79вҶ’	}
 80вҶ’	defer rows.Close()
 81вҶ’
 82вҶ’	items, err := scanItems(rows)
 83вҶ’	if err != nil {
 84вҶ’		return nil, fmt.Errorf("item: list scan: %w", err)
 85вҶ’	}
 86вҶ’
 87вҶ’	return &SearchResult{
 88вҶ’		Items:   items,
 89вҶ’		Total:   total,
 90вҶ’		HasMore: offset+len(items) < total,
 91вҶ’	}, nil
 92вҶ’}
