 94вҶ’// Search performs full-text search over items using the search_vector column.
 95вҶ’func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
 96вҶ’	if query == "" {
 97вҶ’		return &SearchResult{Items: []*Item{}}, nil
 98вҶ’	}
 99вҶ’	limit = clampLimit(limit, maxLimit)
100вҶ’
101вҶ’	qb := &queryBuilder{}
102вҶ’	qb.add("owner_id = $%d", ownerID)
103вҶ’	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
104вҶ’	applyFilter(qb, filter)
105вҶ’	whereClause := qb.where()
106вҶ’
107вҶ’	// Count total matches
108вҶ’	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
109вҶ’	var total int
110вҶ’	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
111вҶ’		return nil, fmt.Errorf("item: search count: %w", err)
112вҶ’	}
113вҶ’
114вҶ’	dataQuery := fmt.Sprintf(
115вҶ’		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
116вҶ’		itemColumns, whereClause, qb.nextParam())
117вҶ’	qb.args = append(qb.args, limit)
118вҶ’
119вҶ’	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
120вҶ’	if err != nil {
121вҶ’		return nil, fmt.Errorf("item: search query: %w", err)
122вҶ’	}
123вҶ’	defer rows.Close()
124вҶ’
125вҶ’	items, err := scanItems(rows)
126вҶ’	if err != nil {
127вҶ’		return nil, fmt.Errorf("item: search scan: %w", err)
128вҶ’	}
129вҶ’
130вҶ’	return &SearchResult{
131вҶ’		Items:   items,
132вҶ’		Total:   total,
133вҶ’		HasMore: len(items) < total,
134вҶ’	}, nil
135вҶ’}
