329вҶ’// UpdateContent updates worker-managed fields (status, title, content) on an item.
330вҶ’// This is used by background jobs, not exposed via GraphQL.
331вҶ’func (s *Service) UpdateContent(ctx context.Context, itemID uuid.UUID, input ContentUpdate) error {
332вҶ’	sets := []string{fmt.Sprintf("status = $%d", 2)}
333вҶ’	args := []any{itemID, input.Status}
334вҶ’	paramIdx := 3
335вҶ’
336вҶ’	if input.Title != nil {
337вҶ’		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
338вҶ’		args = append(args, *input.Title)
339вҶ’		paramIdx++
340вҶ’	}
341вҶ’	if input.ContentText != nil {
342вҶ’		sets = append(sets, fmt.Sprintf("content_text = $%d", paramIdx))
343вҶ’		args = append(args, *input.ContentText)
344вҶ’		paramIdx++
345вҶ’	}
346вҶ’	if input.ContentURL != nil {
347вҶ’		sets = append(sets, fmt.Sprintf("content_url = $%d", paramIdx))
348вҶ’		args = append(args, *input.ContentURL)
349вҶ’		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
350вҶ’	}
351вҶ’
352вҶ’	query := fmt.Sprintf(`UPDATE items SET %s WHERE id = $1`, joinSets(sets))
353вҶ’	tag, err := s.pool.Exec(ctx, query, args...)
354вҶ’	if err != nil {
355вҶ’		return fmt.Errorf("item: update content: %w", err)
356вҶ’	}
357вҶ’	if tag.RowsAffected() == 0 {
358вҶ’		return fmt.Errorf("item: update content: not found")
359вҶ’	}
360вҶ’	return nil
361вҶ’}
362вҶ’
363вҶ’func joinSets(sets []string) string {
364вҶ’	result := ""
365вҶ’	for i, s := range sets {
366вҶ’		if i > 0 {
367вҶ’			result += ", "
368вҶ’		}
369вҶ’		result += s
370вҶ’	}
371вҶ’	return result
372вҶ’}
