 52вҶ’func (w *PageFetchWorker) Work(ctx context.Context, job *river.Job[PageFetchArgs]) error {
 53вҶ’	itemID := job.Args.ItemID
 54вҶ’	url := job.Args.URL
 55вҶ’
 56вҶ’	slog.InfoContext(ctx, "worker: page_fetch: processing",
 57вҶ’		"item_id", itemID,
 58вҶ’		"url", url,
 59вҶ’	)
 60вҶ’
 61вҶ’	// Mark item as processing
 62вҶ’	if err := w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "processing"}); err != nil {
 63вҶ’		return fmt.Errorf("worker: page_fetch: set processing: %w", err)
 64вҶ’	}
 65вҶ’
 66вҶ’	// Fetch and extract content
 67вҶ’	article, err := w.fetchAndExtract(ctx, url)
 68вҶ’	if err != nil {
 69вҶ’		// Set item to error status
 70вҶ’		_ = w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "error"})
 71вҶ’		return fmt.Errorf("worker: page_fetch: fetch: %w", err)
 72вҶ’	}
 73вҶ’
 74вҶ’	// Upload HTML to S3 if storage is configured
 75вҶ’	var contentURL *string
 76вҶ’	if w.Storage != nil && article.Content != "" {
 77вҶ’		key := fmt.Sprintf("items/%s/page.html", itemID)
 78вҶ’		if err := w.Storage.Upload(ctx, key, strings.NewReader(article.Content), "text/html"); err != nil {
 79вҶ’			slog.ErrorContext(ctx, "worker: page_fetch: s3 upload failed, continuing without",
 80вҶ’				"item_id", itemID,
 81вҶ’				"error", err,
 82вҶ’			)
 83вҶ’		} else {
 84вҶ’			contentURL = &key
 85вҶ’		}
 86вҶ’	}
 87вҶ’
 88вҶ’	// Build content update
 89вҶ’	update := item.ContentUpdate{Status: "ready"}
 90вҶ’	if article.Title != "" {
 91вҶ’		update.Title = &article.Title
 92вҶ’	}
 93вҶ’	if article.TextContent != "" {
 94вҶ’		update.ContentText = &article.TextContent
 95вҶ’	}
 96вҶ’	if contentURL != nil {
 97вҶ’		update.ContentURL = contentURL
 98вҶ’	}
 99вҶ’
100вҶ’	if err := w.Items.UpdateContent(ctx, itemID, update); err != nil {
101вҶ’		return fmt.Errorf("worker: page_fetch: update item: %w", err)
102вҶ’	}
103вҶ’
104вҶ’	slog.InfoContext(ctx, "worker: page_fetch: done",
105вҶ’		"item_id", itemID,
106вҶ’		"title", article.Title,
107вҶ’		"text_length", len(article.TextContent),
108вҶ’	)
109вҶ’	return nil
110вҶ’}
