112вҶ’type fetchResult struct {
113вҶ’	Title       string
114вҶ’	TextContent string
115вҶ’	Content     string // HTML content
116вҶ’}
117вҶ’
118вҶ’func (w *PageFetchWorker) fetchAndExtract(ctx context.Context, url string) (*fetchResult, error) {
119вҶ’	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
120вҶ’	if err != nil {
121вҶ’		return nil, fmt.Errorf("build request: %w", err)
122вҶ’	}
123вҶ’	req.Header.Set("User-Agent", userAgent)
124вҶ’
125вҶ’	resp, err := w.httpClient().Do(req)
126вҶ’	if err != nil {
127вҶ’		return nil, fmt.Errorf("http get: %w", err)
128вҶ’	}
129вҶ’	defer func() { _ = resp.Body.Close() }()
130вҶ’
131вҶ’	if resp.StatusCode >= 400 {
132вҶ’		return nil, fmt.Errorf("http status %d for %s", resp.StatusCode, url)
133вҶ’	}
134вҶ’
135вҶ’	article, err := readability.FromReader(resp.Body, nil)
136вҶ’	if err != nil {
137вҶ’		return nil, fmt.Errorf("readability parse: %w", err)
138вҶ’	}
139вҶ’
140вҶ’	return &fetchResult{
141вҶ’		Title:       article.Title,
142вҶ’		TextContent: article.TextContent,
143вҶ’		Content:     article.Content,
144вҶ’	}, nil
145вҶ’}
