 64вҶ’		result.Types = append(result.Types, strings.ToLower(string(t)))
 65вҶ’	}
 66вҶ’	for _, s := range f.Status {
 67вҶ’		result.Status = append(result.Status, strings.ToLower(string(s)))
 68вҶ’	}
 69вҶ’	for _, s := range f.Sensitivity {
 70вҶ’		result.Sensitivity = append(result.Sensitivity, strings.ToLower(string(s)))
 71вҶ’	}
 72вҶ’	result.Tags = f.Tags
